INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (1, 1, 0, 0, 11, 82017, 1, 10, 82, "小さいお子様はともかく、動物さんに\n好かれる自覚はありますし……\n冒険者という仕事に不向きなことも、\n自認していますけれど……", 0);
INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES ("", 0, "", "", 91, 82018, 0, 0, 82, "", "");
